        return { file: fileName, status: 'error', error: `Job ${jobStatus.status}` };
      }

      await new Promise(resolve => setTimeout(resolve, 5000));
    }
  } catch (e: any) {
    return { file: fileName, status: 'error', error: e.message || String(e) };
  }
}

